package com.soumyajit.gradlemc.network;
import net.minecraft.commands.CommandSourceStack;import net.minecraft.network.chat.Component;
public final class NetworkDiagnosticService{private NetworkDiagnosticService(){}public static int status(CommandSourceStack s){var v=NetworkDiagnostics.snapshot();send(s,"GradleMC network metadata: "+v.packets()+"; ignored/rate-limited responses="+v.ignoredResponses());send(s,v.limitation());return 1;}public static int sample(CommandSourceStack s,int seconds){if(!NetworkDiagnostics.start(seconds)){s.sendFailure(Component.literal("A network metadata sample is already active."));return 0;}send(s,"Started "+seconds+"s metadata-only GradleMC channel sample; no payloads or addresses are captured.");return 1;}public static int latest(CommandSourceStack s){var value=NetworkDiagnostics.latest();if(value.isEmpty()){send(s,NetworkDiagnostics.sampling()?"Network sample is still active.":"No completed network sample.");return 1;}var v=value.get();send(s,"Network sample: "+String.format(java.util.Locale.ROOT,"%.2f",v.packetsPerSecond())+" packets/s | "+v.packets()+" | ignored="+v.ignoredResponses());return 1;}private static void send(CommandSourceStack s,String m){s.sendSuccess(()->Component.literal(m),false);}}
